import React, { useState } from 'react';
import { USERS, colorFor, initials } from '../data';
import Avatar from './Avatar';
import styles from './AuthScreen.module.css';

export default function AuthScreen({ onLogin, userList, onRegister }) {
  const [tab, setTab] = useState('login');
  const [loginUser, setLoginUser] = useState('');
  const [loginPass, setLoginPass] = useState('');
  const [loginErr, setLoginErr] = useState('');
  const [regName, setRegName] = useState('');
  const [regUser, setRegUser] = useState('');
  const [regPass, setRegPass] = useState('');
  const [regErr, setRegErr] = useState('');

  function doLogin() {
    const user = userList.find(u => u.username === loginUser.trim().toLowerCase() && u.password === loginPass);
    if (!user) { setLoginErr('Invalid username or password'); return; }
    setLoginErr('');
    onLogin(user);
  }

  function doRegister() {
    if (!regName.trim() || !regUser.trim() || !regPass) { setRegErr('All fields are required'); return; }
    if (userList.find(u => u.username === regUser.trim().toLowerCase())) { setRegErr('Username already taken'); return; }
    const newUser = { id: Date.now(), name: regName.trim(), username: regUser.trim().toLowerCase(), password: regPass };
    onRegister(newUser);
    setRegErr('');
  }

  const demoUsers = USERS.slice(0, 5);

  return (
    <div className={styles.screen}>
      <div className={styles.card}>
        <div className={styles.logo}>
          <div className={styles.logoIcon}>💬</div>
          <h1>Zap Chat</h1>
        </div>

        <div className={styles.tabs}>
          <button className={`${styles.tab} ${tab === 'login' ? styles.active : ''}`} onClick={() => setTab('login')}>Sign in</button>
          <button className={`${styles.tab} ${tab === 'register' ? styles.active : ''}`} onClick={() => setTab('register')}>Sign up</button>
        </div>

        {tab === 'login' && (
          <div>
            <div className={styles.field}>
              <label>Username</label>
              <input type="text" placeholder="your username" value={loginUser}
                onChange={e => setLoginUser(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && doLogin()} autoComplete="off" />
            </div>
            <div className={styles.field}>
              <label>Password</label>
              <input type="password" placeholder="••••••••" value={loginPass}
                onChange={e => setLoginPass(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && doLogin()} />
            </div>
            <button className={styles.btnPrimary} onClick={doLogin}>Sign in →</button>
            <p className={styles.err}>{loginErr}</p>
          </div>
        )}

        {tab === 'register' && (
          <div>
            <div className={styles.field}>
              <label>Full name</label>
              <input type="text" placeholder="Jane Smith" value={regName}
                onChange={e => setRegName(e.target.value)} autoComplete="off" />
            </div>
            <div className={styles.field}>
              <label>Username</label>
              <input type="text" placeholder="janesmith" value={regUser}
                onChange={e => setRegUser(e.target.value)} autoComplete="off" />
            </div>
            <div className={styles.field}>
              <label>Password</label>
              <input type="password" placeholder="••••••••" value={regPass}
                onChange={e => setRegPass(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && doRegister()} />
            </div>
            <button className={styles.btnPrimary} onClick={doRegister}>Create account →</button>
            <p className={styles.err}>{regErr}</p>
          </div>
        )}

        <div className={styles.divider}>or try a demo account</div>

        <div className={styles.demoList}>
          {demoUsers.map(u => {
            const c = colorFor(u.name);
            return (
              <div key={u.id} className={styles.demoItem} onClick={() => onLogin(u)}>
                <div className={styles.demoAvatar} style={{ background: c.bg, color: c.text }}>
                  {initials(u.name)}
                </div>
                <div className={styles.demoInfo}>
                  <strong>{u.name}</strong>
                  <span>@{u.username} / {u.username}</span>
                </div>
                <span className={styles.arrow}>›</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
